import{c as r,Z as o,Q as d,j as i,g as e,n,o as l,m as s}from"./chunks/framework.qjzPVSkb.js";const _=JSON.parse('{"title":"向量数据库","description":"专门存储和检索高维向量的数据库，支持近似最近邻搜索，是 RAG 系统的核心基础设施","frontmatter":{"title":"向量数据库","description":"专门存储和检索高维向量的数据库，支持近似最近邻搜索，是 RAG 系统的核心基础设施","difficulty":"intermediate"},"headers":[],"relativePath":"terms/vector-db.md","filePath":"terms/vector-db.md"}'),h={name:"terms/vector-db.md"};function c(u,t,m,g,b,p){const a=o("DifficultyBadge");return d(),i("div",null,[t[0]||(t[0]=e("h1",{id:"向量数据库",tabindex:"-1"},[n("向量数据库 "),e("a",{class:"header-anchor",href:"#向量数据库","aria-label":'Permalink to "向量数据库"'},"​")],-1)),l(a,{level:"intermediate"}),t[1]||(t[1]=s('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>向量数据库（Vector Database）是专门为<strong>存储和检索高维向量</strong>而设计的数据库，支持高效的<strong>近似最近邻搜索（ANN）</strong>。它让 AI 应用能在海量数据中快速找到与查询语义最相似的内容，是 RAG 系统的核心基础设施。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>传统数据库像电话簿——你按姓名找到号码。向量数据库则像&quot;以图搜图&quot;——你上传一张照片，它找到所有类似的图片。传统搜索是精确匹配，向量搜索是&quot;模糊的相似性匹配&quot;。比如你搜索&quot;便宜的智能手机&quot;，即使数据库里没有完全匹配的词，它也能找到&quot;高性价比手机&quot;&quot;千元旗舰&quot;等相关内容——因为它理解的是语义，而不只是关键词。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>向量数据库的核心技术是<strong>近似最近邻搜索（ANN, Approximate Nearest Neighbor）</strong>——在全量遍历逐一比对（精确但慢）和牺牲少量精度换取极快速度之间取得平衡。主流 ANN 算法包括：</p><ul><li><strong>HNSW（Hierarchical Navigable Small World）</strong>：构建分层图结构，逐层缩小搜索范围，查询速度快且精度高</li><li><strong>IVF（Inverted File Index）</strong>：用聚类将向量分组，搜索时只查附近几个组</li><li><strong>PQ（Product Quantization）</strong>：压缩向量以降低存储和计算开销</li></ul><p>当前主流的向量数据库：</p><table tabindex="0"><thead><tr><th>数据库</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Pinecone</strong></td><td>全托管 SaaS，开箱即用</td><td>快速上线，不想管运维</td></tr><tr><td><strong>Milvus</strong></td><td>开源，功能全面，支持分布式</td><td>大规模生产环境</td></tr><tr><td><strong>Chroma</strong></td><td>轻量级，上手极简，Python 友好</td><td>原型开发、小型项目</td></tr><tr><td><strong>Qdrant</strong></td><td>Rust 编写，性能优秀，支持过滤</td><td>需要复杂过滤条件的场景</td></tr><tr><td><strong>Weaviate</strong></td><td>GraphQL 接口，内置向量化模块</td><td>需要多功能集成的场景</td></tr></tbody></table><p>选择向量数据库时，需要权衡：部署方式（自托管 vs 云服务）、索引性能、过滤能力、生态集成、成本。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/embedding.html">Embedding</a> —— 向量数据库存储的就是 Embedding 生成的向量</li><li><a href="/ai-knowledge/terms/rag.html">RAG</a> —— 向量数据库是 RAG 检索环节的默认选择</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— 向量数据库为 LLM 提供外部知识检索能力</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://milvus.io/docs/index.md" target="_blank" rel="noreferrer">Milvus 文档：向量索引原理</a></li><li><a href="https://www.pinecone.io/learn/vector-database/" target="_blank" rel="noreferrer">Pinecone：What is a Vector Database?</a></li><li>实践建议：入门先用 Chroma 快速验证想法，上线用 Milvus 或 Pinecone 保证性能。</li></ul>',14))])}const q=r(h,[["render",c]]);export{_ as __pageData,q as default};
